int decompress_data(unsigned char *compressed_data, int compressed_len, unsigned char *output_buffer, int output_size) {
    // Check for invalid pointers or negative lengths
    if (compressed_data == NULL || output_buffer == NULL || compressed_len < 0 || output_size < 0) {
        return -1;
    }

    // Handle empty input case
    if (compressed_len == 0) {
        return 0;
    }

    int input_index = 0;   // Current read position in compressed_data
    int output_index = 0;  // Current write position in output_buffer

    // Process all complete 2-byte units while output buffer has space
    while (input_index <= compressed_len - 2 && output_index < output_size) {
        // Read RLE unit: count (1-255) and value
        unsigned char count = compressed_data[input_index];
        unsigned char value = compressed_data[input_index + 1];
        input_index += 2;

        // Validate count (0 is reserved/unused per specification)
        if (count == 0) {
            return -1;
        }

        // Check if run exceeds output buffer capacity
        if (output_index + count > output_size) {
            return -1;
        }

        // Write value 'count' times to output buffer
        for (int i = 0; i < count; i++) {
            output_buffer[output_index++] = value;
        }
    }

    // Return total decompressed bytes on success
    return output_index;
}
